const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

mongoose.connect('mongodb://localhost/testdb', { useNewUrlParser: true, useUnifiedTopology: true });

const UserSchema = new mongoose.Schema({
  name: String,
  age: Number,
  password: String,
  createdAt: Date
});

const User = mongoose.model('User', UserSchema);

async function queryBuilder(filter, projection, sort) {
  try {
    const results = await User.find(filter, projection).sort(sort);
    return results;
  } catch (error) {
    throw error;
  }
}

app.get('/users', async (req, res) => {
  try {
    const filter = req.query.filter ? JSON.parse(req.query.filter) : {};
    const projection = req.query.projection ? JSON.parse(req.query.projection) : {};
    const sort = req.query.sort ? JSON.parse(req.query.sort) : {};

    const users = await queryBuilder(filter, projection, sort);
    res.json(users);
  } catch (error) {
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});